// Parse Geozo API response - same pattern as 01-stats-puller
const raw = $input.first().json;
const statsData = raw?.data?.result?.data || raw?.data || (Array.isArray(raw) ? raw : []);

if (!Array.isArray(statsData) || statsData.length === 0) {
  return [{ json: { error: 'No geo stats', raw_keys: Object.keys(raw || {}), sample: JSON.stringify(raw).slice(0, 300) } }];
}

return statsData.map(d => ({
  json: {
    ad_id: d.ad_id,
    country_code: d.country_code,
    shows: Number(d.shows_count) || 0,
    clicks: Number(d.clicks_count) || 0,
    spend: Math.round((Number(d.money) || 0) * 100) / 100,
    geozo_revenue: Math.round((Number(d.postbacks_confirmed_money) || 0) * 100) / 100
  }
}));

// Join Geozo spend data with CRM revenue
// Parse Geozo items come via $('Parse Geozo Stats'), CRM via $input
const geozoItems = $('Parse Geozo Stats').all().map(i => i.json);
const crmItems = $input.all().map(i => i.json);

// Build CRM map: ad_id+geo -> {leads, depositors, revenue}
const crmMap = {};
crmItems.forEach(row => {
  if (!row.ad_id || !row.geo) return;
  const key = `${row.ad_id}_${row.geo.toUpperCase()}`;
  crmMap[key] = {
    leads: Number(row.total_leads) || 0,
    depositors: Number(row.depositors) || 0,
    revenue: Number(row.crm_revenue) || 0
  };
});

const results = [];
geozoItems.forEach(d => {
  if (!d.ad_id || !d.country_code) return;

  const key = `${d.ad_id}_${d.country_code.toUpperCase()}`;
  const crm = crmMap[key] || { leads: 0, depositors: 0, revenue: 0 };
  const spend = d.spend || 0;
  const roi = spend > 0 ? Math.round((crm.revenue - spend) / spend * 10000) / 100 : 0;

  results.push({
    json: {
      ad_id: d.ad_id,
      country_code: d.country_code,
      shows: d.shows,
      clicks: d.clicks,
      spend: spend,
      revenue: crm.revenue,
      leads: crm.leads,
      depositors: crm.depositors,
      roi: roi
    }
  });
});

if (results.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No data to save', geozo_count: geozoItems.length, crm_count: crmItems.length } }];
}

return results;
